import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
});

// Helper to attach auth token
const withToken = (config = {}) => {
  const token = localStorage.getItem('token');
  if (token) {
    return {
      ...config,
      headers: {
        ...(config.headers || {}),
        Authorization: `Bearer ${token}`,
      },
    };
  }
  return config;
};

export const authAPI = {
  login: (data) => api.post('/auth/login', data),
  register: (data) => api.post('/auth/register', data),
  getCurrentUser: () => api.get('/auth/me', withToken()),
};

export const foodsAPI = {
  getAllFoods: () => api.get('/foods'),
};

export const ordersAPI = {
  getMyOrders: () => api.get('/orders', withToken()),
  createOrder: (data) => api.post('/orders', data, withToken()),
};

export const paymentsAPI = {
  createPayment: (data) => api.post('/payments', data, withToken()),
};

export default api;
